_gad{{_id}}_h = {{n_heads}}
_gad{{_id}}_od = {{out_features}}
_gad{{_id}}_hd = _gad{{_id}}_od // _gad{{_id}}_h
_gad{{_id}}_x = {{features}}
for _gad{{_id}}_step in range({{depth}}):
    _gad{{_id}}_W = np.random.randn(_gad{{_id}}_h, {{in_features}}, _gad{{_id}}_hd).astype(np.float32) * {{init_std}}
    _gad{{_id}}_a_src = np.random.randn(_gad{{_id}}_h, _gad{{_id}}_hd, 1).astype(np.float32) * {{init_std}}
    _gad{{_id}}_a_dst = np.random.randn(_gad{{_id}}_h, _gad{{_id}}_hd, 1).astype(np.float32) * {{init_std}}
    _gad{{_id}}_N = _gad{{_id}}_x.shape[-2]
    _gad{{_id}}_Wh = np.einsum('ni,hio->hno', _gad{{_id}}_x.reshape(_gad{{_id}}_N, -1), _gad{{_id}}_W)
    _gad{{_id}}_e = np.matmul(_gad{{_id}}_Wh, _gad{{_id}}_a_src).squeeze(-1)[:, :, None] + np.matmul(_gad{{_id}}_Wh, _gad{{_id}}_a_dst).squeeze(-1)[:, None, :]
    _gad{{_id}}_e = np.where({{adjacency}} == 0, -1e9, _gad{{_id}}_e)
    _gad{{_id}}_alpha = np.exp(_gad{{_id}}_e - np.max(_gad{{_id}}_e, axis=-1, keepdims=True))
    _gad{{_id}}_alpha /= (_gad{{_id}}_alpha.sum(axis=-1, keepdims=True) + 1e-9)
    _gad{{_id}}_agg = np.matmul(_gad{{_id}}_alpha, _gad{{_id}}_Wh).transpose(1, 0, 2).reshape(_gad{{_id}}_N, _gad{{_id}}_od)
    _gad{{_id}}_x = {{mix_alpha}} * _gad{{_id}}_agg + (1.0 - {{mix_alpha}}) * _gad{{_id}}_x if _gad{{_id}}_x.shape[-1] == _gad{{_id}}_od else _gad{{_id}}_agg
{{output}} = _gad{{_id}}_x
